  materialUsage?: Prisma.MaterialUsageOmit
  invoiceReminder?: Prisma.InvoiceReminderOmit
  invoiceReminderWorkOrder?: Prisma.InvoiceReminderWorkOrderOmit
  assistantConversation?: Prisma.AssistantConversationOmit
  assistantMessage?: Prisma.AssistantMessageOmit
  assistantActionLog?: Prisma.AssistantActionLogOmit
  whatsAppMessage?: Prisma.WhatsAppMessageOmit
